import { NavItem } from "@/data/site";

type NavbarProps = {
  items: NavItem[];
  activeSection: string;
  name: string;
};

export function Navbar({ items, activeSection, name }: NavbarProps) {
  return (
    <header className="sticky top-0 z-50 px-4 pt-4 sm:px-6 lg:px-8">
      <div className="mx-auto flex max-w-6xl flex-col gap-4 rounded-2xl border border-white/10 bg-surface/75 px-4 py-4 shadow-card backdrop-blur-xl sm:flex-row sm:items-center sm:justify-between sm:px-6">
        <a href="#home" className="font-display text-lg font-semibold tracking-tight text-foreground">
          {name}
        </a>

        <nav className="flex flex-wrap items-center gap-2 text-sm text-muted">
          {items.map((item) => {
            const isActive = activeSection === item.sectionId;

            return (
              <a
                key={item.sectionId}
                href={item.href}
                aria-current={isActive ? "page" : undefined}
                className={`rounded-full px-3 py-2 transition duration-300 ${
                  isActive
                    ? "bg-accent text-slate-950"
                    : "bg-white/0 text-muted hover:bg-white/5 hover:text-foreground"
                }`}
              >
                {item.label}
              </a>
            );
          })}
        </nav>
      </div>
    </header>
  );
}
